def gen(rng, size):
    n = max(1, min(size, 400))
    root = None
    def insert(node, v):
        if node is None:
            return {'v': v, 'l': None, 'r': None}
        if v < node['v']:
            node['l'] = insert(node['l'], v)
        else:
            node['r'] = insert(node['r'], v)
        return node
    used = set()
    for _ in range(n):
        v = rng.randint(-100000, 100000)
        while v in used:
            v = rng.randint(-100000, 100000)
        used.add(v)
        root = insert(root, v)
    if rng.random() < 0.5:
        # corrupt one node's value to likely break the BST property
        target = root
        for _ in range(rng.randrange(4)):
            nxt = target['l'] if rng.random() < 0.5 else target['r']
            if nxt is None:
                break
            target = nxt
        target['v'] = rng.randint(-100000, 100000)
    # serialize to level-order with nulls
    arr = []
    queue = [root]
    while queue:
        node = queue.pop(0)
        if node is None:
            arr.append(None)
            continue
        arr.append(node['v'])
        queue.append(node['l'])
        queue.append(node['r'])
    while arr and arr[-1] is None:
        arr.pop()
    return [arr]

