class Solution:
    def isValidBST(self, root):
        vals = []
        def inorder(node):
            if node is None:
                return
            inorder(node.left)
            vals.append(node.val)
            inorder(node.right)
        inorder(root)
        return all(vals[i] < vals[i + 1] for i in range(len(vals) - 1))

