class Solution:
    def isValidBST(self, root):
        def check(node, low, high):
            if node is None:
                return True
            if not (low < node.val < high):
                return False
            return check(node.left, low, node.val) and check(node.right, node.val, high)
        return check(root, float('-inf'), float('inf'))

